pipeline.evaluate:
(async () => {
  const textToInsert = ${{ args.text | json }};
  const box = document.querySelector('[data-testid="tweetTextarea_0"]');
  if (!box) {
    return [{ status: 'failed', message: 'Could not find tweet composer' }];
  }

  const detectCurrentUser = () => {
    const profileHref = document.querySelector('a[data-testid="AppTabBar_Profile_Link"]')?.getAttribute('href') || '';
    const fromProfile = profileHref.replace(/^\//, '').split('/')[0];
    if (/^[A-Za-z0-9_]{1,15}$/.test(fromProfile)) return fromProfile;
    const switcherText = document.querySelector('[data-testid="SideNav_AccountSwitcher_Button"]')?.textContent || '';
    const match = switcherText.match(/@([A-Za-z0-9_]{1,15})/);
    return match?.[1] || '';
  };

  box.focus();
  const dataTransfer = new DataTransfer();
  dataTransfer.setData('text/plain', textToInsert);
  box.dispatchEvent(new ClipboardEvent('paste', {
    clipboardData: dataTransfer,
    bubbles: true,
    cancelable: true
  }));
  await new Promise(r => setTimeout(r, 1000));

  const btn = document.querySelector('[data-testid="tweetButton"]') || document.querySelector('[data-testid="tweetButtonInline"]');
  if (!btn || btn.disabled) {
    return [{ status: 'failed', message: 'Tweet button disabled or not found' }];
  }

  const username = detectCurrentUser();
  btn.click();
  await new Promise(r => setTimeout(r, 4000));

  const urlText = String(location.href || '');
  const tweetId = urlText.match(/\/status\/(\d+)/)?.[1] || '';
  if (tweetId) {
    return [{ status: 'success', message: 'Tweet posted successfully: ' + tweetId }];
  }

  if (username) {
    try {
      location.href = 'https://x.com/' + username;
      await new Promise(r => setTimeout(r, 4000));
      const tweets = Array.from(document.querySelectorAll('[data-testid="tweet"]'));
      const matchTweet = tweets.find(tweet => (tweet.querySelector('[data-testid="tweetText"]')?.textContent || '').includes(textToInsert));
      const href = matchTweet?.querySelector('a[href*="/status/"]')?.href || '';
      const fallbackId = href.match(/\/status\/(\d+)/)?.[1] || '';
      if (fallbackId) {
        return [{ status: 'success', message: 'Tweet posted successfully via profile check: ' + fallbackId }];
      }
    } catch (e) {}
  }

  return [{ status: 'pending', message: 'Tweet action submitted but post could not be verified' }];
})()
